package com.example.app.network;

import okhttp3.OkHttpClient;
import retrofit2.Retrofit;
import retrofit2.converter.gson.GsonConverterFactory;

public class ApiClient {
    public static final String BASE_URL_DEV = "https://api.dev.example.com";
    public static final String BASE_URL_STAGING = "https://api.staging.example.com";
    public static final String BASE_URL_PROD = "https://api.prod.example.com";

    public static Retrofit getRetrofit(String baseUrl) {
        OkHttpClient client = new OkHttpClient.Builder()
                .build();

        return new Retrofit.Builder()
                .baseUrl(baseUrl)
                .client(client)
                .addConverterFactory(GsonConverterFactory.create())
                .build();
    }
}

// Repository class
package com.example.app.data;

import android.util.Log;
import androidx.lifecycle.LiveData;
import androidx.lifecycle.MutableLiveData;
import androidx.paging.DataSource;
import androidx.paging.PagedList;
import retrofit2.Call;
import java.util.List;

public class UserRepository {
    private final ApiClient apiClient;

    public UserRepository(ApiClient apiClient) {
        this.apiClient = apiClient;
    }

    public LiveData<PagedList<User>> getUsers() {
        MutableLiveData<PagedList<User>> data = new MutableLiveData<>();
        DataSource.Factory<Integer, User> dataSourceFactory =
                (dataSourceConfig -> new UsersDataSource(apiClient.getRetrofit(ApiClient.BASE_URL_DEV).create(UserService.class)));

        PagedList.Config config = new PagedList.Config.Builder()
                .setEnablePlaceholders(true)
                .setInitialLoadSizeHint(20)
                .setMaxSize(100)
                .build();

        data.setValue(PagedListLiveData.create(dataSourceFactory, config));
        return data;
    }
}

